@import "@radix-ui/colors/gray.css";
@import "@radix-ui/colors/gray-dark.css";
@import "@radix-ui/colors/orange.css";
@import "@radix-ui/colors/orange-dark.css";
@import "@radix-ui/colors/red.css";
@import "@radix-ui/colors/red-dark.css";
@import "@radix-ui/colors/green.css";
@import "@radix-ui/colors/green-dark.css";
@import "@radix-ui/colors/amber.css";
@import "@radix-ui/colors/amber-dark.css";
@import "@radix-ui/colors/sky.css";
@import "@radix-ui/colors/sky-dark.css";

@custom-variant dark (&:is(.dark *));

@theme {
  /* default → gray */
  --color-default-1:  var(--gray-1);
  --color-default-2:  var(--gray-2);
  --color-default-3:  var(--gray-3);
  --color-default-4:  var(--gray-4);
  --color-default-5:  var(--gray-5);
  --color-default-6:  var(--gray-6);
  --color-default-7:  var(--gray-7);
  --color-default-8:  var(--gray-8);
  --color-default-9:  var(--gray-9);
  --color-default-10: var(--gray-10);
  --color-default-11: var(--gray-11);
  --color-default-12: var(--gray-12);

  /* brand → orange */
  --color-brand-1:    var(--orange-1);
  --color-brand-2:    var(--orange-2);
  --color-brand-3:    var(--orange-3);
  --color-brand-4:    var(--orange-4);
  --color-brand-5:    var(--orange-5);
  --color-brand-6:    var(--orange-6);
  --color-brand-7:    var(--orange-7);
  --color-brand-8:    var(--orange-8);
  --color-brand-9:    var(--orange-9);
  --color-brand-10:   var(--orange-10);
  --color-brand-11:   var(--orange-11);
  --color-brand-12:   var(--orange-12);

  /* error → red */
  --color-error-1:    var(--red-1);
  --color-error-2:    var(--red-2);
  --color-error-3:    var(--red-3);
  --color-error-4:    var(--red-4);
  --color-error-5:    var(--red-5);
  --color-error-6:    var(--red-6);
  --color-error-7:    var(--red-7);
  --color-error-8:    var(--red-8);
  --color-error-9:    var(--red-9);
  --color-error-10:   var(--red-10);
  --color-error-11:   var(--red-11);
  --color-error-12:   var(--red-12);

  /* success → green */
  --color-success-1:  var(--green-1);
  --color-success-2:  var(--green-2);
  --color-success-3:  var(--green-3);
  --color-success-4:  var(--green-4);
  --color-success-5:  var(--green-5);
  --color-success-6:  var(--green-6);
  --color-success-7:  var(--green-7);
  --color-success-8:  var(--green-8);
  --color-success-9:  var(--green-9);
  --color-success-10: var(--green-10);
  --color-success-11: var(--green-11);
  --color-success-12: var(--green-12);

  /* warning → amber */
  --color-warning-1:  var(--amber-1);
  --color-warning-2:  var(--amber-2);
  --color-warning-3:  var(--amber-3);
  --color-warning-4:  var(--amber-4);
  --color-warning-5:  var(--amber-5);
  --color-warning-6:  var(--amber-6);
  --color-warning-7:  var(--amber-7);
  --color-warning-8:  var(--amber-8);
  --color-warning-9:  var(--amber-9);
  --color-warning-10: var(--amber-10);
  --color-warning-11: var(--amber-11);
  --color-warning-12: var(--amber-12);

  /* info → sky */
  --color-info-1:     var(--sky-1);
  --color-info-2:     var(--sky-2);
  --color-info-3:     var(--sky-3);
  --color-info-4:     var(--sky-4);
  --color-info-5:     var(--sky-5);
  --color-info-6:     var(--sky-6);
  --color-info-7:     var(--sky-7);
  --color-info-8:     var(--sky-8);
  --color-info-9:     var(--sky-9);
  --color-info-10:    var(--sky-10);
  --color-info-11:    var(--sky-11);
  --color-info-12:    var(--sky-12);

  --radius: 0.5rem;
  --height-control: 2.25rem;
}

:root {
  /* ─── shadcn default variable overrides → Radix UI ─────────────────────── */
  /* Radix dark CSS imports handle dark mode automatically via .dark scope    */
  --background:            var(--gray-1);
  --foreground:            var(--gray-12);
  --card:                  var(--gray-2);
  --card-foreground:       var(--gray-12);
  --popover:               var(--gray-2);
  --popover-foreground:    var(--gray-12);
  --primary:               var(--orange-9);
  --primary-foreground:    var(--orange-1);
  --secondary:             var(--gray-3);
  --secondary-foreground:  var(--gray-12);
  --muted:                 var(--gray-3);
  --muted-foreground:      var(--gray-11);
  --accent:                var(--gray-3);
  --accent-foreground:     var(--gray-12);
  --destructive:           var(--red-9);
  --destructive-foreground: var(--red-1);
  --border:                var(--gray-6);
  --input:                 var(--gray-7);
  --ring:                  var(--orange-8);

  /* ─── Sidebar ───────────────────────────────────────────────────────────── */
  --sidebar:                    var(--gray-2);
  --sidebar-foreground:         var(--gray-11);
  --sidebar-primary:            var(--orange-9);
  --sidebar-primary-foreground: var(--orange-1);
  --sidebar-accent:             var(--gray-3);
  --sidebar-accent-foreground:  var(--gray-12);
  --sidebar-border:             var(--gray-6);
  --sidebar-ring:               var(--orange-8);
}

@theme inline {
  --color-sidebar:                    var(--sidebar);
  --color-sidebar-foreground:         var(--sidebar-foreground);
  --color-sidebar-primary:            var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent:             var(--sidebar-accent);
  --color-sidebar-accent-foreground:  var(--sidebar-accent-foreground);
  --color-sidebar-border:             var(--sidebar-border);
  --color-sidebar-ring:               var(--sidebar-ring);
}

@layer base {
  * {
    border-color: var(--color-default-6);
  }
  body {
    background-color: var(--color-default-1);
    color: var(--color-default-12);
  }

  button:not(:disabled),
  [role="button"]:not(:disabled) {
    cursor: pointer;
  }
}
